namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly object _lock = new();
    private readonly List<Notification> _notifications = new();

    public NotificationService()
    {
        // Seed with initial fake data
        Add("Welcome to the app!");
        Add("Your profile has been updated.");
        Add("New feature: dark mode is available.");
    }

    public List<Notification> GetAll()
    {
        lock (_lock)
        {
            return _notifications.ToList();
        }
    }

    public List<Notification> GetSince(int lastId)
    {
        lock (_lock)
        {
            return _notifications.Where(n => n.Id > lastId).ToList();
        }
    }

    /// <summary>
    /// Simulates new notifications arriving over time.
    /// Called by a hosted service to generate fake data.
    /// </summary>
    public void GenerateFake()
    {
        string[] messages =
        [
            "You have a new follower.",
            "Someone commented on your post.",
            "Your order has shipped.",
            "Scheduled maintenance tonight at 11 PM.",
            "Your subscription is about to expire.",
            "A new version is available — update now!",
            "Reminder: team standup in 15 minutes.",
        ];

        var msg = messages[Random.Shared.Next(messages.Length)];
        Add(msg);
    }

    private void Add(string message)
    {
        lock (_lock)
        {
            _notifications.Add(new Notification(_nextId++, message, DateTime.UtcNow));
        }
    }
}

namespace NotificationsApp.Services;

/// <summary>
/// Background hosted service that periodically adds fake notifications
/// so the polling page has something new to pick up.
/// </summary>
public class NotificationGeneratorService : BackgroundService
{
    private readonly NotificationService _notifications;

    public NotificationGeneratorService(NotificationService notifications)
    {
        _notifications = notifications;
    }

    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    {
        while (!stoppingToken.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(8), stoppingToken);
            _notifications.GenerateFake();
        }
    }
}

@page "/notifications"
@rendermode @(new InteractiveServerRenderMode(prerender: true))
@using NotificationsApp.Services
@inject NotificationService NotificationSvc
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill">@_notifications.Count</span>
</h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in _notifications)
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <div>
                    <strong>#@n.Id</strong> &mdash; @n.Message
                </div>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> _notifications = new();
    private CancellationTokenSource? _cts;
    private int _lastSeenId;

    // Runs during prerender AND when the circuit starts.
    // On prerender it populates the initial HTML; the list persists into
    // the interactive render so we never re-fetch the same data.
    protected override void OnInitialized()
    {
        _notifications = NotificationSvc.GetAll();
        _lastSeenId = _notifications.Count > 0 ? _notifications.Max(n => n.Id) : 0;
    }

    // Only fires once the component is truly interactive (not during prerender).
    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);
            }
            catch (TaskCanceledException)
            {
                break;
            }

            var newer = NotificationSvc.GetSince(_lastSeenId);
            if (newer.Count > 0)
            {
                _notifications.AddRange(newer);
                _lastSeenId = newer.Max(n => n.Id);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

